interface ApiResponse {
  userId: number;
  id: number;
  title: string;
  body: string;
}

const FetchRequestDemo: React.FC = () => {
  const [data, setData] = useState<ApiResponse | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const controllerRef = useRef<AbortController | null>(null);

  const fetchData = async () => {
    const controller = new AbortController();
    const signal = controller.signal;

    setIsLoading(true);
    setData(null);
    setError(null);
    controllerRef.current = controller;

    try {
      const response = await fetch(
        'https://run.mocky.io/v3/452985b9-a6f7-4738-bfea-74ca3ea6e088?mocky-delay=2000ms',
        { signal }
      );

      if (!response.ok) {
        throw new Error('Failed to load data');
      }

      const result: ApiResponse = await response.json();
      setData(result);
    } catch (err: any) {
      if (err.name === 'AbortError') {
        setError('Request canceled');
      } else {
        setError('Network error');
      }
    } finally {
      setIsLoading(false);
    }
  };

  const cancelRequest = () => {
    if (controllerRef.current) {
      controllerRef.current.abort();
    }
  };

  useEffect(() => {
    fetchData();

    return () => {
      if (controllerRef.current) {
        controllerRef.current.abort();
      }
    };
  }, []);

  return (
    <div style={{ padding: '16px' }}>
      {isLoading && <p style={{ color: 'blue' }}>Loading...</p>}
      {error && <p style={{ color: 'red' }}>{error}</p>}
      {data && (
        <div>
          <h1 style={{ fontSize: '20px', fontWeight: 'bold' }}>Title: {data.title}</h1>
          <p>{data.body}</p>
        </div>
      )}
      <div style={{ marginTop: '16px', display: 'flex', gap: '8px' }}>
        <button
          type="button"
          style={{
            padding: '8px',
            backgroundColor: 'blue',
            color: 'white',
            borderRadius: '4px',
          }}
          onClick={fetchData}
          disabled={isLoading}
        >
          Fetch Again
        </button>
        <button
          type="button"
          style={{
            padding: '8px',
            backgroundColor: 'red',
            color: 'white',
            borderRadius: '4px',
          }}
          onClick={cancelRequest}
          disabled={!isLoading}
        >
          Cancel Request
        </button>
      </div>
    </div>
  );
};

