import axios from 'axios';

interface ApiResponse {
  userId: number;
  id: number;
  title: string;
  body: string;
}

const AxiosRequestDemo = () => {
  const [data, setData] = useState<ApiResponse | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const controllerRef = useRef<AbortController | null>(null);

  const fetchData = async () => {
    const controller = new AbortController();

    setIsLoading(true);
    setData(null);
    setError(null);
    controllerRef.current = controller;

    try {
      const response = await axios.get<ApiResponse>('https://run.mocky.io/v3/452985b9-a6f7-4738-bfea-74ca3ea6e088?mocky-delay=2000ms', {
        signal: controller.signal,
      });

      setData(response.data);
    } catch (err) {
      if (axios.isCancel(err)) {
        setError('Request canceled');
      } else {
        setError('Network error');
      }
    } finally {
      setIsLoading(false);
    }
  };

  const cancelRequest = () => {
    if (controllerRef.current) {
      controllerRef.current.abort();
    }
  };

  useEffect(() => {
    fetchData();

    return () => {
      if (controllerRef.current) {
        controllerRef.current.abort();
      }
    };
  }, []);

  return (
    <div style={{ padding: '16px' }}>
      {isLoading && <p>Loading...</p>}
      {error && <p style={{ color: 'red' }}>{error}</p>}
      {data && (
        <div>
          <h1 style={{ fontSize: '20px', fontWeight: 'bold' }}>Title: {data.title}</h1>
          <p>{data.body}</p>
        </div>
      )}
      <div style={{ marginTop: '16px', display: 'flex', gap: '8px' }}>
        <button
          type="button"
          style={{
            padding: '8px',
            backgroundColor: 'blue',
            color: 'white',
            borderRadius: '4px',
          }}
          onClick={fetchData}
          disabled={isLoading}
        >
          Fetch Again
        </button>
        <button
          type="button"
          style={{
            padding: '8px',
            backgroundColor: 'red',
            color: 'white',
            borderRadius: '4px',
          }}
          onClick={cancelRequest}
          disabled={!isLoading}
        >
          Cancel Request
        </button>
      </div>
    </div>
  );
};

