import { createImperativePromise, ImperativePromise } from 'awesome-imperative-promise'; // \u5047\u8BBE\u4F60\u5DF2\u7ECF\u5B9A\u4E49\u597D\u8FD9\u4E2A\u5E93

interface ApiResponse {
  userId: number;
  id: number;
  title: string;
  body: string;
}

const PromiseCancelDemo = () => {
  const [data, setData] = useState<ApiResponse | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const requestPromiseRef = useRef<ImperativePromise<ApiResponse> | null>(null);

  const fetchData = () => {
    const { promise, resolve, reject, cancel } = createImperativePromise<ApiResponse>();
    requestPromiseRef.current = { promise, resolve, reject, cancel };

    setIsLoading(true);
    setData(null);
    setError(null);

    fetch('https://run.mocky.io/v3/452985b9-a6f7-4738-bfea-74ca3ea6e088?mocky-delay=2000ms')
      .then(response => {
        if (!response.ok) {
          throw new Error('Failed to load data');
        }
        return response.json();
      })
      .then(resolve)
      .catch(error => {
        if (error.name !== 'AbortError') {
          reject(error);
        }
      });

    promise
      .then((result) => {
        setData(result);
      })
      .catch((error) => {
        setError('Network error');
      })
      .finally(() => {
        setIsLoading(false);
      });
  };

  const cancelRequest = () => {
    if (requestPromiseRef.current) {
      requestPromiseRef.current.cancel();
      setError('Request canceled');
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchData();

    return () => {
      if (requestPromiseRef.current) {
        requestPromiseRef.current.cancel();
      }
    };
  }, []);

  return (
    <div style={{ padding: '16px' }}>
      {isLoading && <p>Loading...</p>}
      {error && <p style={{ color: 'red' }}>{error}</p>}
      {data && (
        <div>
          <h1 style={{ fontSize: '20px', fontWeight: 'bold' }}>Title: {data.title}</h1>
          <p>{data.body}</p>
        </div>
      )}
      <div style={{ marginTop: '16px', display: 'flex', gap: '8px' }}>
        <button
          type="button"
          style={{
            padding: '8px',
            backgroundColor: 'blue',
            color: 'white',
            borderRadius: '4px',
          }}
          onClick={fetchData}
          disabled={isLoading}
        >
          Fetch Again
        </button>
        <button
          type="button"
          style={{
            padding: '8px',
            backgroundColor: 'red',
            color: 'white',
            borderRadius: '4px',
          }}
          onClick={cancelRequest}
          disabled={!isLoading}
        >
          Cancel Request
        </button>
      </div>
    </div>
  );
};

