const ScriptComponent = () => {
  const runScript = () => {
    async function async2() {
      alert('async2');
    }

    async function async1() {
      alert('async1 start');
      await async2();
      alert('async1 end');
    }

    alert('script start');

    setTimeout(function () {
      alert('setTimeout');
    }, 0);

    async1();

    new Promise(function (resolve) {
      alert('promise1');
      resolve();
    }).then(function () {
      alert('promise2');
    });

    alert('script end');
  };

  return (
    <div className="p-4">
      <button type="button" onClick={runScript}>
        \u6253\u5370\u987A\u5E8F\u662F\u4EC0\u4E48\uFF1F
      </button>
    </div>
  );
};

