`,paraId:26,tocIndex:14},{value:"\u53EF\u4EE5\u7528\u663E\u793A\u7684 ",paraId:27,tocIndex:14},{value:"queueMicrotask",paraId:27,tocIndex:14},{value:" \u51FD\u6570\u6765\u6DFB\u52A0 microtask \u6765\u6A21\u62DF\uFF1A",paraId:27,tocIndex:14},{value:`// \u6267\u884C\u6B65\u9AA4

// task \u6267\u884C
// queueMicrotask \u89E6\u53D1\u5668 1 \u4F1A\u628A\u56DE\u8C03\u6DFB\u52A0\u5230\u5FAE\u4EFB\u52A1\u961F\u5217
// queueMicrotask \u89E6\u53D1\u5668 3 \u4F1A\u628A\u56DE\u8C03\u6DFB\u52A0\u5230\u5FAE\u4EFB\u52A1\u961F\u5217
// \u5FAE\u4EFB\u52A1\u961F\u5217\u5F00\u59CB\u6267\u884C
// \u6253\u5370 1\uFF0CqueueMicrotask \u89E6\u53D1\u5668 2 \u4F1A\u628A\u56DE\u8C03\u6DFB\u52A0\u5230\u5FAE\u4EFB\u52A1\u961F\u5217
// \u6253\u5370 3\uFF0CqueueMicrotask \u89E6\u53D1\u5668 4 \u4F1A\u628A\u56DE\u8C03\u6DFB\u52A0\u5230\u5FAE\u4EFB\u52A1\u961F\u5217
// \u6253\u5370 2\uFF0C\u6253\u5370 4

queueMicrotask(() => { // 1
  console.log(1)
  queueMicrotask(() => { // 2
    console.log(2)
  })
})

queueMicrotask(() => { // 3
  console.log(3)
  queueMicrotask(() => { // 4
    console.log(4)
  })
})
