function App() {
  const [state] = useState(0);
  console.log(1);

  // \u4E00\u6BB5\u5360\u7528 react 50 ms \u7684\u4EFB\u52A1
  const start = Date.now();
  while (Date.now() - start < 50) {
    window.timestamp = Date.now();
  }

  useEffect(() => {
    console.log(2);
  }, [state]);

  Promise.resolve().then(() => {
    console.log(3);
  });

  setTimeout(() => {
    console.log(4);
  }, 0);

  return null;
}

export default App;
`,paraId:12,tocIndex:3},{value:"\u524D\u5F80 ",paraId:13,tocIndex:3},{value:"Deeper Dive Into React",paraId:13,tocIndex:3},{value:" \u4F53\u9A8C\u4EA4\u4E92\u5F0F\u7B54\u9898\u3002",paraId:13,tocIndex:3},{value:"\u70B9\u51FB\u5C55\u793A\u7B54\u6848",paraId:3},{value:"\u5BF9\u4E8E\u5982\u4E0B\u7EC4\u4EF6\uFF0C",paraId:14,tocIndex:4},{value:"console.log",paraId:14,tocIndex:4},{value:" \u7684\u6253\u5370\u987A\u5E8F\u662F\u4EC0\u4E48\uFF1F",paraId:14,tocIndex:4},{value:`/**
 * iframe: true
*/

import { useEffect, useState, useLayoutEffect } from 'react';

function App() {
  const [state, setState] = useState(0);
  console.log(1);

  // \u4E00\u6BB5\u5360\u7528 react 50 ms \u7684\u4EFB\u52A1
  const start = Date.now();
  while (Date.now() - start < 50) {
    window.timestamp = Date.now();
  }

  useEffect(() => {
    console.log(2);
  }, [state]);

  Promise.resolve().then(() => {
    console.log(3);
  });

  setTimeout(() => {
    console.log(4);
  }, 0);

  useLayoutEffect(() => {
    console.log(5);
    setState((state) => state + 1);
  }, []);

  return null;
}

export default App;
