// function
// \u5FC5\u987B\u5199\u8FD4\u56DE\u503C\u7C7B\u578B
const sum: (a: number, b: number) => number = (a, b) => a + b
// \u8FD4\u56DE\u503C\u53EF\u4EE5\u63A8\u65AD\u51FA\u6765
const minus = (a: number, b: number) => a - b + ''

// JSON \u5E8F\u5217\u5316
const response = { name: 'chu', age: 28 }
