// \u7531\u4E8E {} \u5C31\u662F\u4E00\u4E2A\u7A7A\u5BF9\u8C61\uFF0C\u56E0\u6B64\u9664 null\u3001undefined \u4EE5\u5916\u7684\u4E00\u5207\u57FA\u7840\u7C7B\u578B\uFF0C\u90FD\u53EF\u4EE5\u88AB\u89C6\u4E3A\u662F\u7EE7\u627F\u4E8E {} \u4E4B\u540E\u6D3E\u751F\u51FA\u6765\u7684\u3002
